// src/lib/photo-editor/stickers/catalogue.ts
//
// Curated Twemoji catalogue — ~800 emoji across 9 categories.
// Generated by scripts/build-sticker-catalogue.py.
// Each entry holds the lowercase Twemoji codepoint string, a display
// label, and a list of search keywords. Codepoint strings join multi-
// codepoint sequences (flags, ZWJ) with "-".
//
// Twemoji CDN filename rule (verified empirically against
// cdn.jsdelivr.net/gh/twitter/twemoji@latest/assets/svg/):
//   • Single-codepoint emojis: just the base codepoint, FE0F stripped
//     (e.g. "26a0" for ⚠️, "1f3d7" for 🏗️).
//   • Skin-toned variants: BASE-TONE (e.g. "1f44d-1f3fc").
//   • ZWJ + object profession (e.g. mechanic): BASE-200d-OBJECT, no
//     FE0F (e.g. "1f9d1-200d-1f527").
//   • ZWJ + gender (♂/♀): MUST keep the trailing "-fe0f" (e.g.
//     "1f477-200d-2642-fe0f"). The FE0F variation selector forces
//     emoji presentation on the gender signs which would otherwise
//     render as text characters.
//
// Construction category (added later): a curated 200-entry set of
// the most useful emojis for UK construction-context users —
// tools, PPE, plant, hazards, status markers, etc. Some entries
// are deliberately duplicated from other categories (e.g. 🔨 also
// lives in Objects) so users browsing the Construction tab don't
// have to hunt elsewhere for tools they expect to find here.

export type StickerCategoryId =
  | "recents"
  | "construction"
  | "smileys"
  | "animals"
  | "food"
  | "travel"
  | "activities"
  | "objects"
  | "symbols"
  | "flags";

export interface StickerCategory {
  id: Exclude<StickerCategoryId, "recents">;
  label: string;
  /** Codepoint of the emoji used as the tab icon. */
  iconCodepoint: string;
  count: number;
}

export interface StickerEntry {
  /** Twemoji codepoint string (e.g. "1f600", "1f1ec-1f1e7"). */
  codepoint: string;
  label: string;
  keywords: readonly string[];
  category: Exclude<StickerCategoryId, "recents">;
}

