export const STICKERS_BY_CATEGORY: Readonly<Record<
  Exclude<StickerCategoryId, "recents">,
  readonly StickerEntry[]
>> = {
  construction: CONSTRUCTION_ENTRIES,
  smileys: SMILEYS_ENTRIES,
  animals: ANIMALS_ENTRIES,
  food: FOOD_ENTRIES,
  travel: TRAVEL_ENTRIES,
  activities: ACTIVITIES_ENTRIES,
  objects: OBJECTS_ENTRIES,
  symbols: SYMBOLS_ENTRIES,
  flags: FLAGS_ENTRIES,
};

/** Flat list of every catalogue entry. Order is category-sequential. */
export const ALL_STICKERS: readonly StickerEntry[] = [
  ...CONSTRUCTION_ENTRIES,
  ...SMILEYS_ENTRIES,
  ...ANIMALS_ENTRIES,
  ...FOOD_ENTRIES,
  ...TRAVEL_ENTRIES,
  ...ACTIVITIES_ENTRIES,
  ...OBJECTS_ENTRIES,
  ...SYMBOLS_ENTRIES,
  ...FLAGS_ENTRIES,
];

const BY_CODEPOINT = new Map<string, StickerEntry>(
  ALL_STICKERS.map((entry) => [entry.codepoint, entry] as const),
);

/** Look up an entry by codepoint. Returns null if not in the catalogue. */
export function findStickerByCodepoint(codepoint: string): StickerEntry | null {
  return BY_CODEPOINT.get(codepoint.toLowerCase()) ?? null;
}

/** Case-insensitive keyword + label search. Empty query returns []. */
export function searchStickers(query: string): StickerEntry[] {
  const q = query.trim().toLowerCase();
  if (q.length === 0) return [];
  return ALL_STICKERS.filter((entry) => {
    if (entry.label.toLowerCase().includes(q)) return true;
    return entry.keywords.some((kw) => kw.includes(q));
  });
}
